141:       most_specific_header_mutations_wins_(config.most_specific_header_mutations_wins()) {}
142: 
143: void HeaderMutation::maybeInitializeRouteConfigs(Http::StreamFilterCallbacks* callbacks) {
144:   // Ensure that route configs are initialized only once and the same route configs are used
145:   // for both decoding and encoding paths.
146:   // An independent flag is used to ensure even at the case where the route configs is empty,
147:   // we still won't try to initialize it again.
148:   if (route_configs_initialized_) {
149:     return;
150:   }
151:   route_configs_initialized_ = true;
152: 
153:   // Traverse through all route configs to retrieve all available header mutations.
154:   // `getAllPerFilterConfig` returns in ascending order of specificity (i.e., route table
155:   // first, then virtual host, then per route).
156:   route_configs_ = Http::Utility::getAllPerFilterConfig<PerRouteHeaderMutation>(callbacks);
157: 
158:   // The order of returned route configs is route table first, then virtual host, then
159:   // per route. That means the per route configs will be evaluated at the end and will
160:   // override the more general virtual host and route table configs.
161:   //
162:   // So, if most_specific_header_mutations_wins is false, we need to reverse the order
163:   // of route configs.
164:   if (!config_->mostSpecificHeaderMutationsWins()) {
165:     std::reverse(route_configs_.begin(), route_configs_.end());
166:   }
167: }
168: 
169: Http::FilterHeadersStatus HeaderMutation::decodeHeaders(Http::RequestHeaderMap& headers, bool) {
170:   Formatter::HttpFormatterContext context{&headers};
171:   config_->mutations().mutateRequestHeaders(headers, context, decoder_callbacks_->streamInfo());
172: 
173:   maybeInitializeRouteConfigs(decoder_callbacks_);
174: 
175:   for (const PerRouteHeaderMutation& route_config : route_configs_) {
176:     route_config.mutations().mutateRequestHeaders(headers, context,
177:                                                   decoder_callbacks_->streamInfo());
178:   }
179: 
180:   return Http::FilterHeadersStatus::Continue;
181: }
182: 
183: Http::FilterHeadersStatus HeaderMutation::encodeHeaders(Http::ResponseHeaderMap& headers, bool) {
184:   Formatter::HttpFormatterContext context{encoder_callbacks_->requestHeaders().ptr(), &headers};
185:   config_->mutations().mutateResponseHeaders(headers, context, encoder_callbacks_->streamInfo());
186: 
187:   // Note if the filter before this one has send local reply then the decodeHeaders() will not be
188:   // be called and the route config will not be initialized. Try it again here and it will be
189:   // no-op if already initialized.
190:   maybeInitializeRouteConfigs(encoder_callbacks_);
191: 
192:   for (const PerRouteHeaderMutation& route_config : route_configs_) {
193:     route_config.mutations().mutateResponseHeaders(headers, context,
194:                                                    encoder_callbacks_->streamInfo());
195:   }
196: 
197:   return Http::FilterHeadersStatus::Continue;
198: }
199: 
200: Http::FilterTrailersStatus HeaderMutation::encodeTrailers(Http::ResponseTrailerMap& trailers) {
201:   Formatter::HttpFormatterContext context{encoder_callbacks_->requestHeaders().ptr(),
202:                                           encoder_callbacks_->responseHeaders().ptr(), &trailers};
203:   config_->mutations().mutateResponseTrailers(trailers, context, encoder_callbacks_->streamInfo());
204: 
205:   maybeInitializeRouteConfigs(encoder_callbacks_);
206: 
207:   for (const PerRouteHeaderMutation& route_config : route_configs_) {
208:     route_config.mutations().mutateResponseTrailers(trailers, context,
209:                                                     encoder_callbacks_->streamInfo());
210:   }
211:   return Http::FilterTrailersStatus::Continue;
212: }
213: 
214: Http::FilterTrailersStatus HeaderMutation::decodeTrailers(Http::RequestTrailerMap& trailers) {
215:   // TODO(davinci26): if `HttpFormatterContext` supports request trailers we can also pass the
216:   // trailers to the context so we can support substitutions from other trailers.
217:   Formatter::HttpFormatterContext context{encoder_callbacks_->requestHeaders().ptr()};
218:   config_->mutations().mutateRequestTrailers(trailers, context, encoder_callbacks_->streamInfo());
219: 
220:   maybeInitializeRouteConfigs(encoder_callbacks_);
221: 
222:   for (const PerRouteHeaderMutation& route_config : route_configs_) {
223:     route_config.mutations().mutateRequestTrailers(trailers, context,
224:                                                    encoder_callbacks_->streamInfo());
225:   }
226:   return Http::FilterTrailersStatus::Continue;
227: }
