783: void Utility::encodeLocalReply(const bool& is_reset, PreparedLocalReplyPtr prepared_local_reply) {
784:   ASSERT(prepared_local_reply != nullptr);
785:   ResponseHeaderMapPtr response_headers{std::move(prepared_local_reply->response_headers_)};
786: 
787:   if (prepared_local_reply->is_grpc_request_) {
788:     // Trailers only response
789:     prepared_local_reply->encode_headers_(std::move(response_headers), true);
790:     return;
791:   }
792: 
793:   if (prepared_local_reply->is_head_request_) {
794:     prepared_local_reply->encode_headers_(std::move(response_headers), true);
795:     return;
796:   }
797: 
798:   const bool bodyless_response = prepared_local_reply->response_body_.empty();
799:   prepared_local_reply->encode_headers_(std::move(response_headers), bodyless_response);
800:   // encode_headers() may have changed the referenced is_reset so we need to test it
801:   if (!bodyless_response && !is_reset) {
802:     Buffer::OwnedImpl buffer(prepared_local_reply->response_body_);
803:     prepared_local_reply->encode_data_(buffer, true);
804:   }
805: }
